CustomField.formula:
/*jirs ov-336   SAP Actual Ship Date - Data Mapping ID#31 is present then show status CR with dates*/
IF(NOT(ISBLANK(Actual_Customer_Date__c )) && NOT(ISBLANK(Actual_CER_date__c)), "Order Shipped",

/*SAP Estimated Ship Date - Data Mapping ID#29 is present then show status OS with dates*/
IF(NOT(ISBLANK(Current_Global_Delivery_Date__c)) && NOT(ISBLANK(Actual_Global_Delivery_Date__c)), "Ready for Shipping",

/*SAP Order Id is present and Credit Status is Not equal to Credit Hold and Global Delivery Date is present*/
IF(NOT(ISBLANK(Current_Global_Delivery_Date__c)), "Mfg Date Committed",

/*When SAP Order Id is present and Credit Status is Not equal to Credit Hold*/
IF(Credit_Status_Name__c="Approved"  && ISBLANK(Delivery_Block__c) && ISBLANK(Delivery_Block_Description__c) &&  fxBlockedItems__c=0, "Order Clear",

/*Order status when its “Closed”, “Won” opportunity with SAP Order Id*/
IF(NOT(ISBLANK(Name)), "Processing Hold", "")
)
)
)
)
